class FollErrService {
    static async GetMachineConfig(machine_id?: number): Promise<MachineConfigFoll[]> {
        let uri = `${BASE_URL}/api/extension/following_error/v1/machine`
        if (machine_id != null) {
            uri += `?machine_id=${machine_id}`
        }

        const resp = await FetchUtils.fetchAuth(uri)
        if (resp.status !== 200) {
            throw new Error(resp.message)
        }

        if (!Array.isArray(resp.data)) {
            throw new Error("invalid machine config response")
        }
        for (let i = 0; i < resp.data.length; i++) {
            const row = resp.data[i]
            if (typeof row.machine_id != "number") { throw new Error("invalid machine_id value") }
            if (typeof (row.following_error_warn ?? 0) != "number") { throw new Error("invalid following_error_warn value") }
            if (typeof (row.following_error_alarm ?? 0) != "number") { throw new Error("invalid following_error_alarm value") }
        }

        return resp.data
    }

    static async UpsertMachineConfig(machine_id: number, fields: FormMachineConfigFoll): Promise<{ message: string }> {
        const resp = await FetchUtils.fetchAuth(`${BASE_URL}/api/extension/following_error/v1/machine`, {
            method: 'PATCH',
            body: JSON.stringify({ machine_id, fields }),
            headers: { "Content-Type": "application/json" }
        })

        if (resp.status !== 200) {
            throw new Error(resp.message)
        }

        return resp
    }
}

